#!/bin/bash
# Reply to an existing message via work-buddy's messaging service.
# This script is auto-generated by check_messages.sh on session start.
# Session ID and sender are pre-configured — you don't need to provide them.

SERVICE_URL="%%SERVICE_URL%%"
SENDER="%%SENDER%%"
SENDER_SESSION="%%SESSION%%"

usage() {
    cat <<'HELP'
Usage: bash /tmp/wb/reply [OPTIONS]

Reply to a message via work-buddy's messaging service.
The reply automatically inherits the thread and routes to the original sender.

Required:
  --id <message-id>      ID of the message to reply to (shown in message summaries)
  --body <text>           Reply body content

Optional:
  --type <type>           Message type (default: ack)
                          Values: ack, status-update, question, result, escalation, directive
  --priority <level>      Priority level (default: normal)
                          Values: low, normal, high, urgent
  --help                  Show this help message

Examples:
  bash /tmp/wb/reply --id 20260403T044932-work-buddy-c8ea288b --body "Sounds good, will do."
  bash /tmp/wb/reply --id 20260403T044932-work-buddy-c8ea288b --type question --body "Can you clarify what you mean?"
HELP
    exit 0
}

# Parse arguments
MSG_ID=""
BODY=""
TYPE="ack"
PRIORITY="normal"

while [ $# -gt 0 ]; do
    case "$1" in
        --id)       MSG_ID="$2"; shift 2 ;;
        --body)     BODY="$2"; shift 2 ;;
        --type)     TYPE="$2"; shift 2 ;;
        --priority) PRIORITY="$2"; shift 2 ;;
        --help|-h)  usage ;;
        *)          echo "Unknown option: $1. Use --help for usage."; exit 1 ;;
    esac
done

# Validate required args
if [ -z "$MSG_ID" ]; then echo "Error: --id is required. Use --help for usage."; exit 1; fi
if [ -z "$BODY" ]; then echo "Error: --body is required. Use --help for usage."; exit 1; fi

# Pass body via stdin to preserve UTF-8 (Git Bash mangles non-ASCII in sys.argv)
echo "$BODY" | python -c "
import json, sys, urllib.request, urllib.error

body = sys.stdin.read().strip()
msg = {
    'sender': sys.argv[1],
    'sender_session': sys.argv[2],
    'body': body,
    'type': sys.argv[3],
    'priority': sys.argv[4],
}

url = sys.argv[5] + '/messages/' + sys.argv[6] + '/reply'
data = json.dumps(msg).encode('utf-8')
req = urllib.request.Request(url, data=data, method='POST')
req.add_header('Content-Type', 'application/json')

try:
    with urllib.request.urlopen(req, timeout=5) as resp:
        result = json.loads(resp.read().decode('utf-8'))
        print('Replied:', result['id'], 'in thread', result['thread_id'])
except urllib.error.URLError as e:
    print(f'Error: Could not reach messaging service. Is it running?', file=sys.stderr)
    sys.exit(1)
except Exception as e:
    print(f'Error: {e}', file=sys.stderr)
    sys.exit(1)
" "$SENDER" "$SENDER_SESSION" "$TYPE" "$PRIORITY" "$SERVICE_URL" "$MSG_ID"
